import React from 'react';
import cuLogo from './assets/logo.png';

const PreviewDoc = React.forwardRef(function PreviewDoc(
  { tpl, studentName, uid, section, worksheetNo, datePerf, sectionContent, outputImages = [], outputBlocks = [] },
  ref
) {
  return (
    <div
      ref={ref}
      id="pdf-preview-root"
      style={{
        background: '#ffffff',
        color: '#111111',
        fontFamily: `'${tpl.bodyFont}', sans-serif`,
        fontSize: `${tpl.fontSize}pt`,
        lineHeight: tpl.spacing,
        textAlign: tpl.align,
        padding: '36px 52px',
        width: '794px',
        minHeight: '1123px',
        boxSizing: 'border-box',
        margin: '0 auto',
      }}
    >
      {/* ── CU Department Header ── */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 18,
        borderBottom: '2.5px solid #111',
        paddingBottom: 12, marginBottom: 14,
      }}>
        {/* Logo Box */}
        <img
  src={cuLogo}
  alt="CU Logo"
  style={{
    width: 70,
    height: 70,
    objectFit: 'contain',
    borderRadius: 6,
  }}
/>

        {/* Department Text */}
        <div style={{ flex: 1 }}>
          <div style={{
            color: '#cc0000', fontWeight: 700,
            fontSize: `${tpl.fontSize - 1}pt`, letterSpacing: '0.06em',
            marginBottom: 2,
          }}>
            DEPARTMENT OF
          </div>
          <div style={{
            fontWeight: 900,
            fontSize: `${tpl.fontSize + 9}pt`,
            letterSpacing: '0.01em',
            lineHeight: 1.15,
            color: '#111',
          }}>
            COMPUTER SCIENCE &amp; ENGINEERING
          </div>
          <div style={{
            borderTop: '1px solid #bbb', marginTop: 6, paddingTop: 5,
            color: '#555', fontStyle: 'italic',
            fontSize: `${tpl.fontSize - 1}pt`,
          }}>
            Discover. Learn. Empower.
          </div>
        </div>
      </div>

      {/* ── Worksheet Title ── */}
      <div style={{ textAlign: 'center', marginBottom: 14 }}>
        <div style={{
          fontFamily: `'${tpl.headingFont}', serif`,
          fontSize: `${tpl.fontSize + 5}pt`,
          fontWeight: 700,
          textDecoration: 'underline',
        }}>
          Worksheet {worksheetNo}
        </div>
      </div>

      {/* ── Student Info Table ── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 16, fontSize: `${tpl.fontSize}pt` }}>
        <tbody>
          {[
            [['Student Name', studentName], ['UID', uid]],
            [['Branch', tpl.branch],        ['Section/Group', section]],
            [['Semester', tpl.semester],    ['Date of Performance', datePerf]],
            [['Subject Name', tpl.subject], ['Subject Code', tpl.subjectCode]],
          ].map((row, ri) => (
            <tr key={ri}>
              {row.map(([k, v]) => (
                <td key={k} style={{ padding: '2px 0', width: '50%' }}>
                  <strong>{k}:</strong> {v}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>

      {/* ── Sections ── */}
      {tpl.sections.map((sec, i) => {
        const isOutput = sec.toLowerCase() === 'output';
        return (
          <div key={sec} style={{ marginBottom: 16 }}>
            {/* Section heading */}
            <div style={{
              fontFamily: `'${tpl.headingFont}', serif`,
              fontSize: `${tpl.fontSize + 1}pt`,
              fontWeight: 700,
              marginBottom: 4,
              borderBottom: '1px solid #ddd',
              paddingBottom: 2,
            }}>
              {i + 1}. {sec}:
            </div>

            {/* Output section: render each block individually */}
            {isOutput && outputBlocks.length > 0 ? (
              <div>
                {outputBlocks.map((block, idx) => (
                  <div key={idx} style={{ marginBottom: 14 }}>
                    {/* Output block label */}
                    {outputBlocks.length > 1 && (
                      <div style={{
                        fontSize: `${tpl.fontSize - 1}pt`,
                        fontWeight: 700,
                        color: '#444',
                        marginBottom: 3,
                      }}>
                        Output {idx + 1}:
                      </div>
                    )}

                    {/* Text content */}
                    {block.text && (
                      <div style={{
                        whiteSpace: 'pre-wrap',
                        fontSize: `${tpl.fontSize}pt`,
                        paddingLeft: 4,
                        marginBottom: block.imageUrl ? 8 : 0,
                      }}>
                        {block.text}
                      </div>
                    )}

                    {/* Image */}
                    {block.imageUrl && (
                      <div style={{ textAlign: 'center', marginTop: 8 }}>
                        <img
                          src={block.imageUrl}
                          alt={`Output ${idx + 1}`}
                          style={{
                            maxWidth: '100%',
                            maxHeight: 260,
                            objectFit: 'contain',
                            border: '1px solid #ddd',
                            borderRadius: 4,
                            display: 'block',
                            margin: '0 auto',
                          }}
                        />
                        <div style={{
                          fontSize: `${tpl.fontSize - 2}pt`,
                          color: '#888', marginTop: 4, fontStyle: 'italic',
                        }}>
                          Fig {idx + 1}: {block.imageName ? block.imageName.replace(/\.[^.]+$/, '') : `Output ${idx + 1}`}
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            ) : (
              /* All non-output sections */
              <div style={{
                whiteSpace: 'pre-wrap',
                fontSize: `${tpl.fontSize}pt`,
                paddingLeft: 4,
                fontFamily: sec.toLowerCase().includes('code') ? 'monospace' : 'inherit',
              }}>
                {sectionContent[sec] || <span style={{ color: '#aaa', fontStyle: 'italic' }}>(no content)</span>}
              </div>
            )}

            {/* Legacy outputImages fallback (if outputBlocks not passed) */}
            {isOutput && outputBlocks.length === 0 && outputImages.length > 0 && (
              <div style={{ marginTop: 10, display: 'flex', flexWrap: 'wrap', gap: 12 }}>
                {outputImages.map((img, idx) => (
                  <div key={idx} style={{ textAlign: 'center' }}>
                    <img
                      src={img.dataUrl}
                      alt={`Output ${idx + 1}`}
                      style={{
                        maxWidth: '100%', maxHeight: 260,
                        objectFit: 'contain', border: '1px solid #ddd',
                        borderRadius: 4, display: 'block',
                      }}
                    />
                    <div style={{ fontSize: `${tpl.fontSize - 2}pt`, color: '#888', marginTop: 4, fontStyle: 'italic' }}>
                      Fig {idx + 1}: {img.name.replace(/\.[^.]+$/, '')}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
});

export default PreviewDoc;
